import java.io.*; // Import the necessary Java packages – io.* package provides Input/Output streams, exceptions handling etc., whereas util* packaged provide utility classes such file handles reading a list of files in directory or other operations which does not need exception processing like IOException (used for input and output stream)等
import java.nio.file.*; // Provides the Path interface to represent paths based on different types supported by platform, similar as File but more portable – unlike FilenameFilter you can filter using lambda expression or method references etc., whereas file system operations like moving a directory are not in this package so it's used for reading list of files from given path.
import java.util.*; // Import the necessary Java classes to handle lists and maps, such as ArrayList which provides an implementation with default empty element factory – unlike LinkedList you can provide custom linked nodes or add listener etc., whereas HashMap is a type-safe key/value store where every operation takes constant time complexity O(1).
import java.util.stream.*; // Streams are not provided in standard libraries, they're present from Java8 onwards but only available if you have support for them and your IDE supports it – similar to Iterator or Collection views we provide these classes which allow iterating over collection of objects etc., as well like parallel operations